const AllIntents = () => (
  <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
    <AlButton intent="primary">Primary</AlButton>
    <AlButton intent="secondary">Secondary</AlButton>
    <AlButton intent="danger">Danger</AlButton>
