  </div>
);

const NoLabel = () => {
  const form = useForm<FormData>({
    resolver: zodResolver(schema),
    mode: 'onBlur',
  });
  return (
    <AlInput<FormData>
      name="email"
      form={form}
      placeholder="Input sem label"
      type="email"
    />
  );
};

const TwoLevels = () => <AlBreadcrumbs
    items={[
      { text: 'Painel', link: '/dashboard' },
      { text: 'Configurações' },
    ]} />;

const CustomSeparator = () => <AlBreadcrumbs
    items={[
      { text: 'Início', link: '/' },
      { text: 'Usuários', link: '/users' },
      { text: 'John Doe' },
    ]}
    separator="›" />;

const Default = () => <AlCarousel>{[
      <div key="1" style={slideStyle('#22c55e')}>Slide 1</div>,
      <div key="2" style={slideStyle('#3b82f6')}>Slide 2</div>,
      <div key="3" style={slideStyle('#f97316')}>Slide 3</div>,
    ]}</AlCarousel>;

const WithIntent = () => <AlCarousel intent="primary">{[
      <div key="1" style={slideStyle('#22c55e')}>Slide 1</div>,
      <div key="2" style={slideStyle('#3b82f6')}>Slide 2</div>,
    ]}</AlCarousel>;

const AutoPlay = () => <AlCarousel autoPlay={3000}>{[
      <div key="1" style={slideStyle('#22c55e')}>Auto 1</div>,
      <div key="2" style={slideStyle('#3b82f6')}>Auto 2</div>,
      <div key="3" style={slideStyle('#ef4444')}>Auto 3</div>,
    ]}</AlCarousel>;

const Default = () => {
  const [active, setActive] = useState(0);
  const steps = [
    { label: 'Informações Pessoais', content: <div><h3>Passo 1: Informações Pessoais</h3><p>Preencha seu nome e dados de contato.</p></div> },
    { label: 'Endereço', content: <div><h3>Passo 2: Endereço</h3><p>Informe seu endereço de entrega.</p></div> },
    { label: 'Pagamento', content: <div><h3>Passo 3: Pagamento</h3><p>Insira os dados de pagamento.</p></div> },
    { label: 'Revisão', content: <div><h3>Passo 4: Revisão</h3><p>Revise e confirme seu pedido.</p></div> },
  ];

  return (
    <div>
      <AlStepper steps={steps} activeStep={active} onStepChange={setActive} />
      <div style={{ display: 'flex', gap: '12px', marginTop: '16px' }}>
        <AlButton intent="secondary" onClick={() => setActive(Math.max(0, active - 1))} disabled={active === 0}>
          Voltar
        </AlButton>
        <AlButton onClick={() => setActive(Math.min(steps.length - 1, active + 1))} disabled={active === steps.length - 1}>
          Próximo
        </AlButton>
      </div>
    </div>
  );
};

const SimpleTable = () => {
  const table = useAlTable({ data: data.slice(0, 5), columns });
  return <AlTable table={table} />;
};

const WithSorting = () => {
  const table = useAlTable({ data, columns, enableSorting: true });
  return <AlTable table={table} />;
};

const WithPagination = () => {
  const table = useAlTable({ data, columns, enablePagination: true, pageSize: 10 });
  return <AlTable table={table} />;
};

const SortingAndPagination = () => {
  const table = useAlTable({
    data,
    columns,
    enableSorting: true,
    enablePagination: true,
    pageSize: 10,
  });
  return <AlTable table={table} />;
};

const GroupedColumns = () => {
  const groupedColumns = [
    columnHelper.group({
      header: 'Name',
      columns: [
        columnHelper.accessor('firstName', { header: 'Nome' }),
        columnHelper.accessor('lastName', { header: 'Sobrenome' }),
      ],
    }),
    columnHelper.group({
      header: 'Info',
      columns: [
        columnHelper.accessor('age', { header: 'Idade' }),
        columnHelper.accessor('email', { header: 'Email' }),
        columnHelper.accessor('department', { header: 'Depto' }),
      ],
    }),
  ];
  const table = useAlTable({ data: data.slice(0, 10), columns: groupedColumns, enableSorting: true });
  return <AlTable table={table} />;
};

const EmptyState = () => {
  const table = useAlTable({ data: [], columns });
  return <AlTable table={table} emptyMessage="Nenhum funcionário encontrado" />;
};

const InlineEditing = () => {
  const editableColumns = [
    columnHelper.accessor('firstName', {
      header: 'Nome',
      cell: ({ getValue }) => {
        const initialValue = getValue();
        return (
          <input
            className="al-input"
            defaultValue={initialValue}
            onBlur={() => {}}
            style={{ width: '100%', padding: '4px 8px', fontSize: 'inherit' }}
          />
        );
      },
    }),
    columnHelper.accessor('lastName', { header: 'Sobrenome' }),
    columnHelper.accessor('age', { header: 'Idade' }),
    columnHelper.accessor('email', { header: 'Email' }),
  ];
  const table = useAlTable({ data: data.slice(0, 5), columns: editableColumns });
  return <AlTable table={table} />;
};
